# checkers_game.py

def print_board(board):
    for row in board:
        print(" ".join(row))

def initialize_board():
    board = [['.' for _ in range(8)] for _ in range(8)]
    for i in range(3):
        for j in range(0, 8, 2):
            board[i][j] = 'B'
    for i in range(5, 8):
        for j in range(1, 9, 2):
            board[i][j] = 'W'
    return board

def get_valid_moves(board, player):
    valid_moves = []
    for row in range(8):
        for col in range(8):
            if (board[row][col] == 'B' and player == 'black') or (board[row][col] == 'W' and player == 'white'):
                valid_moves.extend(get_moves(board, row, col, player))
    return valid_moves

def get_moves(board, row, col, player):
    moves = []
    directions = [(-1, -1), (-1, 1), (1, -1), (1, 1)]
    if player == 'black':
        for dr, dc in directions:
            r, c = row + dr * 2, col + dc * 2
            if not (0 <= r < 8 and 0 <= c < 8):
                continue
            if board[r][c] == '.':
                moves.append((row, col, r, c))
            elif board[r][c].isupper() and abs(r - row) == 2:
                r, c = row + dr, col + dc
                if board[r][c] == ('W' if player == 'black' else 'B'):
                    moves.append((row, col, r, c))
    elif player == 'white':
        for dr, dc in directions:
            r, c = row + dr * 2, col + dc * 2
            if not (0 <= r < 8 and 0 <= c < 8):
                continue
            if board[r][c] == '.':
                moves.append((row, col, r, c))
            elif board[r][c].islower() and abs(r - row) == 2:
                r, c = row + dr, col + dc
                if board[r][c] == ('w' if player == 'white' else 'b'):
                    moves.append((row, col, r, c))
    return moves

def make_move(board, start_row, start_col, end_row, end_col):
    piece = board[start_row][start_col]
    board[end_row][end_col] = piece
    board[start_row][start_col] = '.'
    if abs(start_row - end_row) == 2:
        mid_row, mid_col = (start_row + end_row) // 2, (start_col + end_col) // 2
        board[mid_row][mid_col] = '.'

def is_game_over(board):
    black_moves = get_valid_moves(board, 'black')
    white_moves = get_valid_moves(board, 'white')
    return not black_moves and not white_moves

def main():
    board = initialize_board()
    player = 'black'
    while True:
        print_board(board)
        if is_game_over(board):
            print("Game Over! " + ('Black wins' if player == 'black' else 'White wins'))
            break
        start_col, start_row, end_col, end_row = map(int, input(f"Player {player}, enter move (from-to positions): ").split())
        if (start_row, start_col, end_row, end_col) in get_valid_moves(board, player):
            make_move(board, start_row, start_col, end_row, end_col)
            player = 'black' if player == 'white' else 'white'
        else:
            print("Invalid move. Try again.")

if __name__ == "__main__":
    main()
```

